      ["Independent Variable", "A variable that is changed or controlled in an experiment or analysis to test its effects on a dependent variable."],
      ["Dependent Variable", "A variable that is observed and measured to see how it responds to changes in an independent variable."],
      ["Cause-and-Effect Relationship", "The relationship where changes in an independent variable produce changes in a dependent variable."],
      ["Current Ratio", "A liquidity ratio calculated as current assets divided by current liabilities, indicating short-term financial strength."],
      ["Acid-Test Ratio (Quick Ratio)", "A measure of liquidity excluding inventory; (cash + receivables + marketable securities) / current liabilities."],
      ["Debt Ratio", "Total liabilities divided by total assets, showing the proportion of assets financed by debt."],
      ["Working Capital", "Current assets minus current liabilities, indicating available short-term resources."],
      ["Equity Ratio", "Total equity divided by total assets, showing the proportion of assets financed by owners."],
      ["Earnings per Share (EPS)", "Net income available to common shareholders divided by the number of outstanding shares."],
      ["Financial Strength Analysis", "The evaluation of a company’s ability to meet obligations, maintain solvency, and generate returns."],
      ["Liquidity", "The ability of a company to meet short-term obligations with current assets."],
      ["Solvency", "The ability of a company to meet long-term obligations and continue operations."],
      ["Leverage", "The use of debt to finance assets, measured by ratios like debt-to-equity or debt ratio."],
      ["Profitability", "The ability to generate earnings relative to revenue, assets, or equity."],
      ["Example: Change in Independent Variable", "Increasing advertising budget (independent) may lead to higher sales (dependent)."],
      ["Example: Current Ratio Calculation", "Current assets $50,000, current liabilities $25,000; current ratio = 2.0."],
      ["Example: Acid-Test Ratio Calculation", "Cash $10,000, receivables $15,000, current liabilities $20,000; quick ratio = 1.25."],
      ["Example: Debt Ratio", "Total liabilities $40,000, total assets $100,000; debt ratio = 0.4."],
      ["Example: Working Capital", "Current assets $60,000 minus current liabilities $20,000 = $40,000 working capital."],
      ["Example: Equity Ratio", "Equity $60,000 divided by total assets $100,000 = 0.6 or 60% equity ratio."],
      ["Example: EPS Calculation", "Net income $50,000, 10,000 shares outstanding; EPS = $5.00 per share."],
      ["Horizontal Analysis", "Comparing financial data across periods to observe trends and changes."],
      ["Vertical Analysis", "Expressing financial statement items as a percentage of a base amount to analyze proportions."],
      ["Example: Horizontal Analysis", "Revenue $50,000 this year vs $45,000 last year; increase = 11.1%."],
      ["Example: Vertical Analysis", "COGS $30,000, sales $50,000; COGS = 60% of sales."],
      ["Example: Independent Variable Impact on Dependent Variable", "Raising product price may decrease sales quantity."],
      ["Example: Debt Ratio Impact", "High debt ratio indicates greater financial risk for creditors and investors."],
      ["Example: Working Capital Insight", "Positive working capital indicates company can cover short-term obligations."],
      ["Example: Quick Ratio Insight", "Quick ratio above 1 indicates adequate short-term liquidity without relying on inventory."],
      ["Example: Equity Ratio Insight", "High equity ratio suggests lower financial risk and stronger solvency."],
      ["Example: EPS Impact", "Increasing net income or reducing shares outstanding increases EPS, indicating higher profitability."],
      ["Example: Change in Price on Demand", "Independent variable (price) increase leads to dependent variable (quantity demanded) decrease."],
      ["Example: Increase in Assets", "If assets increase but liabilities stay the same, current ratio and working capital improve."],
      ["Example: Increase in Liabilities", "Higher liabilities may reduce equity ratio and working capital."],
      ["Example: Change in Net Income", "Increase in net income raises EPS and can improve equity ratio."],
      ["Example: Liquidity Decision", "Investor assesses current and quick ratios before providing short-term loans."],
      ["Example: Solvency Decision", "Lender evaluates debt ratio and equity ratio before issuing long-term financing."],
      ["Example: Profitability Decision", "Management analyzes EPS and profit margins to plan expansion or dividends."],
      ["Example: Effect of Accounts Receivable Increase", "Increase in receivables raises current assets and current ratio, improving liquidity."],
      ["Example: Effect of Inventory Increase", "Increase in inventory raises current assets, improving current ratio but may not affect quick ratio."],
      ["Example: Horizontal Trend Analysis", "Revenue increasing 10% per year signals positive growth trend."],
      ["Example: Vertical Analysis Insight", "Expressing expenses as % of sales identifies cost efficiency."],
      ["Example: Debt Ratio Caution", "Debt ratio >1 indicates more liabilities than assets, risky for solvency."],
      ["Example: EPS Comparison", "Comparing EPS across years indicates profitability trends."],
      ["Example: Working Capital Management", "Reducing liabilities or increasing assets improves working capital."],
      ["Example: Acid-Test Decision", "Quick ratio <1 suggests company may struggle to meet short-term obligations."],
      ["Example: Independent Variable Experiment", "Changing interest rates (independent) affects loan demand (dependent)."],
      ["Example: Equity Ratio Adjustment", "Issuing new equity increases equity ratio, reduces leverage."],
      ["Example: Using Ratios for Investment Decision", "Investors select companies with strong liquidity, low debt, and high EPS."],
      ["Example: Combined Financial Strength", "Analyzing current ratio, quick ratio, debt ratio, and EPS together for full financial picture."],
      ["Example: Scenario: Sales Increase", "Increase in sales (independent) improves net income, EPS, and equity ratio (dependent)."],
      ["Example: Scenario: Large Purchase on Credit", "Liabilities increase, working capital may decrease, affecting liquidity ratios."],
      ["Example: Scenario: Paying Off Debt", "Liabilities decrease, debt ratio decreases, equity ratio increases, improving financial strength."],
      ["Example: Trend Analysis", "Using horizontal analysis to see 5-year increase in current ratio and net income."],
      ["Example: Ratio Benchmarking", "Compare company ratios to industry standards to assess performance."],
      ["Example: EPS Decision", "Company considers stock split if EPS is high to increase affordability for investors."],
      ["Example: Acid-Test Ratio Limitation", "Excludes inventory, may understate liquidity if inventory is easily liquidated."],
      ["Example: Working Capital Limitation", "High working capital may indicate excess idle assets."],
      ["Example: Analyzing Dependent Variable Response", "Observe how net income (dependent) changes when sales volume (independent) is increased."]
