      ["Variable Costs", "Costs that change in direct proportion to the level of production or sales volume."],
      ["Fixed Costs", "Costs that remain constant regardless of the level of production or sales volume."],
      ["Mixed Costs", "Costs that contain both fixed and variable components."],
      ["Contribution Margin", "Sales revenue minus variable costs; represents amount available to cover fixed costs and profit."],
      ["Contribution Margin Ratio", "Contribution margin divided by sales, expressed as a percentage."],
      ["Break-Even Point", "The sales level at which total revenues equal total costs, resulting in zero profit."],
      ["Break-Even in Units", "Fixed Costs ÷ Contribution Margin per Unit."],
      ["Break-Even in Dollars", "Fixed Costs ÷ Contribution Margin Ratio."],
      ["Target Profit Analysis", "Determining the sales volume required to achieve a desired profit."],
      ["Margin of Safety", "The excess of actual or projected sales over break-even sales."],
      ["Cost-Volume-Profit (CVP) Analysis", "Examining the effects of changes in costs and volume on profit."],
      ["Operating Leverage", "The degree to which fixed costs are used, indicating sensitivity of profit to sales changes."],
      ["High-Low Method", "A technique to separate fixed and variable components of mixed costs using highest and lowest activity levels."],
      ["Sales Revenue", "Income generated from selling goods or services."],
      ["Total Costs", "The sum of variable and fixed costs for a given level of production or sales."],
      ["Example: Variable Cost Calculation", "If $5 per unit and 1,000 units produced, total variable costs = $5 × 1,000 = $5,000."],
      ["Example: Fixed Cost Identification", "Rent $2,000/month remains the same regardless of units produced."],
      ["Example: Mixed Cost Analysis", "Electricity $500 fixed + $0.05 per unit variable component."],
      ["Example: Contribution Margin per Unit", "Selling price $50 − variable cost $30 = $20 contribution margin per unit."],
      ["Example: Contribution Margin Ratio", "Contribution margin $20 ÷ sales price $50 = 40%."],
      ["Example: Break-Even Units", "Fixed costs $10,000 ÷ $20 contribution margin per unit = 500 units."],
      ["Example: Break-Even Sales Dollars", "Fixed costs $10,000 ÷ 40% contribution margin ratio = $25,000."],
      ["Example: Target Profit Units", "(Fixed Costs + Target Profit) ÷ Contribution Margin per Unit."],
      ["Example: Margin of Safety in Units", "Actual sales 600 units − break-even 500 units = 100 unit margin of safety."],
      ["Example: Margin of Safety in Dollars", "Actual sales $30,000 − break-even $25,000 = $5,000 margin of safety."],
      ["Example: CVP Graph", "X-axis units sold, Y-axis dollars; show total revenue, total costs, and break-even point."],
      ["Example: Operating Leverage", "High fixed costs increase sensitivity of net income to changes in sales volume."],
      ["Example: High-Low Method Calculation", "Highest cost $12,000 at 2,000 units, lowest $8,000 at 1,000 units; variable cost/unit = ($12,000 − $8,000)/(2,000−1,000) = $4/unit."],
      ["Real-Life Scenario: Pricing Decision", "Use contribution margin and break-even analysis to set minimum selling price."],
      ["Real-Life Scenario: Cost Control", "Identify fixed and variable components to manage costs effectively."],
      ["Example: Sales Increase Impact", "Higher sales increase contribution margin and profit above break-even point."],
      ["Example: Cost Reduction Impact", "Lower variable costs increase contribution margin per unit, lowering break-even point."],
      ["Example: Break-Even with Multiple Products", "Use weighted average contribution margin for mixed product lines."],
      ["Example: Sensitivity Analysis", "Test changes in price, cost, or volume to see effect on break-even and profit."],
      ["Example: Fixed vs Variable Expense Analysis", "Categorize expenses like rent (fixed) and materials (variable) for CVP modeling."],
      ["Example: Mixed Cost Component Separation", "Electricity bill $1,000; $500 fixed, $0.10/unit variable; use high-low method to separate."],
      ["Example: Contribution Margin and Profit Planning", "Ensure contribution margin covers fixed costs and desired profit."],
      ["Example: Break-Even Chart Interpretation", "Intersection of total revenue and total costs lines indicates break-even."],
      ["Example: Target Profit in Dollars", "(Fixed Costs + Target Profit) ÷ Contribution Margin Ratio."],
      ["Example: Margin of Safety Percentage", "Margin of safety ÷ actual sales × 100; e.g., $5,000 ÷ $30,000 = 16.7%."],
      ["Real-Life Scenario: Seasonal Sales Planning", "Use break-even and CVP to plan for high and low season cash flow."],
      ["Example: Contribution Margin for Special Orders", "Determine if selling below normal price still covers variable costs."],
      ["Example: Break-Even with Discounts", "Recalculate contribution margin after discount to find new break-even units."],
      ["Example: CVP Spreadsheet Analysis", "Use formulas to compute break-even, contribution margin, and target profit automatically."],
      ["Example: Cost-Volume-Profit Sensitivity", "Assess how changes in costs or sales volume impact profitability."],
      ["Example: Variable Cost Adjustment", "Change in raw material cost affects contribution margin per unit and break-even."],
      ["Example: Fixed Cost Adjustment", "Increase in rent raises break-even sales required to cover costs."],
      ["Example: Operating Leverage Scenario", "High fixed cost structure amplifies profit when sales rise, but losses when sales drop."],
      ["Example: Multi-Scenario Analysis", "Model best-case, worst-case, and expected sales to evaluate risk."],
      ["Example: Break-Even with Multiple Cost Drivers", "Use separate contribution margins for different product lines or services."],
      ["Example: Practical CVP Use", "Assess new product profitability using contribution margin and break-even analysis."],
      ["Example: Profit Planning with Mixed Costs", "Separate fixed and variable components to determine accurate sales targets."],
      ["Example: Graphical Interpretation", "Plot total revenue and total costs to visualize break-even and profit areas."],
      ["Example: Contribution Margin Decision-Making", "Focus on products with higher contribution margins to increase overall profit."],
      ["Example: Break-Even Analysis in Spreadsheets", "Use cell formulas to compute units, dollars, and target profit efficiently."],
      ["Example: Real-Life Small Business", "Owner calculates break-even units to determine minimum sales needed each month."],
      ["Example: Mixed Cost in Production", "Utility bill partially fixed, partially variable; impacts break-even calculation."],
      ["Example: Sensitivity to Cost Changes", "Analyze how increases in variable cost per unit change break-even volume."]
   ,
     ["Materials Ledger", "A detailed record showing the quantity and cost of raw materials purchased, used, and remaining."],
      ["Finished Goods Ledger", "A record tracking completed products, including quantities produced, costs, and inventory balances."],
      ["Cost Accounting Software", "Software used to record, process, and analyze manufacturing costs and inventory data."],
      ["Direct Materials", "Raw materials directly traceable to the production of finished goods."],
      ["Direct Labor", "Wages paid to workers directly involved in manufacturing products."],
      ["Manufacturing Overhead", "Indirect production costs, including indirect materials, labor, and factory expenses."],
      ["Work in Process (WIP)", "Inventory of partially completed goods still in production."],
      ["Cost of Goods Manufactured (COGM)", "Total cost of all goods completed during a period, including materials, labor, and overhead."],
      ["Cost of Goods Sold (COGS)", "The cost of finished goods sold during a period, transferred from finished goods ledger to income statement."],
      ["Inventory Control", "Processes to monitor and manage inventory levels, costs, and movements accurately."],
      ["Departmentalized Accounting", "System that records and reports financial transactions by departments or cost centers."],
      ["Overhead Allocation", "Assigning indirect costs to products or departments using a predetermined rate or method."],
      ["Predetermined Overhead Rate", "Estimated overhead divided by estimated activity base to allocate costs to products or departments."],
      ["Job Costing", "Tracking costs of materials, labor, and overhead for individual jobs or batches."],
      ["Process Costing", "Recording and assigning costs for continuous mass production processes."],
      ["Example: Materials Ledger Entry", "Purchase of $5,000 raw materials: Debit Materials Inventory $5,000, Credit Accounts Payable $5,000."],
      ["Example: Materials Ledger Usage", "Deduct raw materials used for production to update WIP inventory."],
      ["Example: Finished Goods Ledger Entry", "Transfer completed goods: Debit Finished Goods $10,000, Credit WIP $10,000."],
      ["Example: Cost Allocation in Ledger", "Apply overhead $3,000 to WIP based on predetermined rate: Debit WIP $3,000, Credit Manufacturing Overhead $3,000."],
      ["Example: Direct Materials Recorded", "Materials $6,000 used in production entered into WIP in the ledger."],
      ["Example: Direct Labor Recorded", "Labor $7,500 charged to WIP for production work."],
      ["Example: Finished Goods Update", "Add completed products to finished goods ledger, adjusting balances accordingly."],
      ["Example: COGS Entry from Ledger", "Debit COGS $16,000, Credit Finished Goods $16,000 for goods sold."],
      ["Example: Departmentalized Ledger", "Separate cost tracking for assembly, packaging, and quality control departments."],
      ["Real-Life Scenario: Software Ledger Automation", "Use software to update materials and finished goods ledgers automatically after each transaction."],
      ["Real-Life Scenario: Multiple Department Costs", "Track expenses and production costs by department for more accurate cost control."],
      ["Example: Overhead Applied Using Software", "Input rate and activity base into software to assign overhead to jobs automatically."],
      ["Example: Materials Ledger Balance", "Shows beginning inventory + purchases − materials used = ending balance."],
      ["Example: Finished Goods Ledger Balance", "Shows beginning FG + completed goods − goods sold = ending balance."],
      ["Example: Multi-Department Allocation", "Allocate overhead costs to multiple departments proportionally based on labor hours."],
      ["Example: Job Costing with Software", "Record materials, labor, and overhead for each job; software calculates total cost."],
      ["Example: Process Costing with Software", "Aggregate costs across continuous production for total period costs automatically."],
      ["Example: Cost Reports from Software", "Generate departmental or job reports showing total costs, variances, and inventory balances."],
      ["Example: Software Adjustment Entries", "Automatically adjust applied vs actual overhead at period-end in software."],
      ["Example: Tracking Material Usage", "Record all withdrawals from inventory to WIP for accurate ledger balances."],
      ["Example: Finished Goods Transfer", "Software posts WIP to finished goods when production is completed."],
      ["Example: Departmental Ledger Reports", "Show costs incurred, cost allocation, and departmental totals for management review."],
      ["Example: Overhead Variance Tracking", "Software calculates difference between applied and actual overhead for adjustments."],
      ["Example: Cost per Unit Calculation", "Software computes cost per unit using ledger data from materials, labor, and overhead."],
      ["Example: Multi-Period Ledger Review", "Track changes in materials and finished goods over several periods for trend analysis."],
      ["Example: Real-Time Inventory Tracking", "Software updates ledger balances in real time as transactions occur."],
      ["Example: Cost Center Reporting", "Generate reports for individual departments showing assigned costs and performance."],
      ["Real-Life Scenario: Reducing Errors", "Using software for ledgers minimizes manual entry mistakes in cost accounting."],
      ["Example: Allocating Shared Costs", "Distribute shared overhead like utilities among departments based on activity usage."],
      ["Example: Material Requisition Recording", "Software records materials withdrawn for jobs and adjusts inventory automatically."],
      ["Example: Labor Allocation to Departments", "Direct labor charged to specific departments in the ledger for accurate costing."],
      ["Example: Finished Goods Valuation", "Compute ending finished goods inventory cost using materials, labor, and applied overhead."],
      ["Example: Departmental Performance Evaluation", "Compare departmental costs to budget using ledger reports."],
      ["Example: Adjusting Entries for Overhead", "Post adjustments in software to reconcile applied vs actual overhead by department."],
      ["Example: Multi-Product Ledger Tracking", "Track costs for multiple products simultaneously in materials and finished goods ledgers."],
      ["Example: End-of-Year Ledger Summary", "Summarize all departmental and inventory costs for financial reporting."],
      ["Example: Cost Control Using Ledgers", "Analyze ledger balances to identify overspending or inefficiencies."],
      ["Example: Software Integration with Accounting", "Link ledgers to general ledger for seamless financial reporting."],
      ["Example: Real-Life Small Business Use", "Small manufacturer tracks materials and finished goods in software to reduce errors and streamline reporting."],
      ["Example: Variance Analysis Using Ledgers", "Compare actual material/labor costs to standards to detect inefficiencies."],
      ["Example: Automated Allocation", "Software automatically applies overhead to WIP and departments using predetermined rates."],
      ["Example: Spreadsheet Ledger Maintenance", "Use Excel or specialized software to maintain and update ledgers efficiently."],
      ["Example: Multi-Department Allocation Adjustment", "Adjust allocations for departments with over/under applied overhead at period-end."],
      ["Example: Inventory and Cost Reports", "Generate periodic reports for management decision-making and production planning."]
